using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to use this agent.");
var modelId = Environment.GetEnvironmentVariable("OPENAI_CHAT_MODEL") ?? "gpt-4o-mini";

// --- Tools ---
var researchTools = new ResearchTools();
var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// --- Agent setup ---
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Interactive loop ---
Console.WriteLine("🔬 Research Agent (type 'quit' to exit)");
Console.WriteLine("Enter a topic to research:\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\n🔍 Researching \"{topic}\"...\n");

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. Given a topic you must:
            1. Search the web 2-3 times with varied queries to gather broad information.
            2. Save the most important findings as notes using the note-taking tool.
            3. Retrieve all your notes and synthesize them into a clear, comprehensive summary.
            Be thorough but concise. Cite sources when possible.
            """),
        new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"),
    ];

    try
    {
        var response = await client.GetResponseAsync(messages, chatOptions);
        Console.WriteLine("\n📄 Summary:\n");
        Console.WriteLine(response.Text);
    }
    catch (Exception ex)
    {
        Console.WriteLine($"❌ Error: {ex.Message}");
    }

    researchTools.ClearNotes();
    Console.WriteLine();
}

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------
sealed class ResearchTools
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _http = new();

    [Description("Search the web for a query and return relevant results.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await _http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            var abs = root.GetProperty("Abstract").GetString();
            var absSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                results.Add($"[{absSource}] {abs}");

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text))
                        results.Add(text.GetString() ?? "");
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try a different or more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note for later reference.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content")] string content)
    {
        Console.WriteLine($"  📝 Saving note: \"{title}\"");
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
    }

    public void ClearNotes() => _notes.Clear();
}

